-- 006: Restaurants vertical — /eat and /eat/:slug.
-- Restaurants fit the existing generalized schema (immutable rule #2 in
-- CLAUDE.md): no new tables. This migration widens `listings` to carry a
-- slug + theme + freeform config, then seeds the 10 restaurants from
-- _incoming/restaurant-template-engine.jsx and _incoming/seed_restaurants.js.
--
-- NOTE: db/migrations/ is missing 002-004 (hotel seed + the guests-select
-- RLS fix referenced in CLAUDE.md's hard-won lessons) — they were applied
-- directly in Supabase and never committed here. This migration is written
-- defensively around that gap: the listing_type check-constraint rename is
-- looked up dynamically rather than assumed, and no existing RLS is
-- disabled or narrowed. Before running, check pg_policies for name
-- collisions with the policy added at the bottom, and re-test the hotel
-- booking flow from an anonymous/incognito session afterward.

-- ------------------------------------------------------------------
-- 1. Widen listings.listing_type to allow 'restaurant'.
-- The constraint name is looked up rather than assumed, since the table
-- was created in 001_init_schema.sql with an inline (unnamed) check and
-- Postgres's default-naming convention, while reliable, isn't worth
-- gambling a migration on.
-- ------------------------------------------------------------------
do $$
declare
  cname text;
begin
  select conname into cname
  from pg_constraint
  where conrelid = 'listings'::regclass
    and contype = 'c'
    and pg_get_constraintdef(oid) ilike '%listing_type%';

  if cname is not null then
    execute format('alter table listings drop constraint %I', cname);
  end if;

  alter table listings add constraint listings_listing_type_check
    check (listing_type in ('room', 'tour', 'vehicle', 'table', 'restaurant'));
end $$;

-- ------------------------------------------------------------------
-- 2. New columns on listings: slug (stable, lowercase-hyphenated, used by
-- /eat/:slug), theme_id (selects a preset from features/restaurants/themes.js),
-- site_config (the full restaurant config: tagline, cuisine, story, menu,
-- hours, gallery — see api.js's mapListingToRestaurant for the read shape).
-- ------------------------------------------------------------------
alter table listings add column if not exists slug text;
alter table listings add column if not exists theme_id text default 'enda-mama';
alter table listings add column if not exists site_config jsonb not null default '{}'::jsonb;

-- ------------------------------------------------------------------
-- 3. Backfill slugs for pre-existing (hotel) listings so the column can
-- eventually become NOT NULL. Hotel room-type listings have no slug
-- concept in the app today (hotel routing is by partner id), so these are
-- generated, not curated: "<hotel>-<room type>" plus a short id suffix to
-- guarantee uniqueness even where names collide across hotels (e.g. two
-- "Standard Room" listings).
-- ------------------------------------------------------------------
update listings l
set slug = trim(both '-' from lower(regexp_replace(p.name || '-' || l.name, '[^a-zA-Z0-9]+', '-', 'g')))
           || '-' || substr(l.id::text, 1, 8)
from partners p
where l.partner_id = p.id
  and l.slug is null;

-- ------------------------------------------------------------------
-- 4. Seed data: 10 fictional restaurants (is_seed: true in site_config —
-- same convention as the seed hotels). 3 from the prototype
-- (restaurant-template-engine.jsx), 7 from seed_restaurants.js.
-- Bar Vittoria has no theme_id in the prototype (theme was picked via the
-- dev preview dropdown there); assigned 'asmarina' here for the literal
-- art-deco-ceiling match against that theme's mood.
-- ------------------------------------------------------------------
