  ((select id from partners where name = 'Adulis Kitchen' and business_type = 'restaurant'), 'restaurant', 'adulis-kitchen', 'Adulis Kitchen', 'Traditional Eritrean dining in the heart of Asmara', false, 'enda-mama', '{"tagline":"Traditional Eritrean dining in the heart of Asmara","cuisine":"Eritrean · Traditional","est":1987,"story":["For nearly four decades, Adulis Kitchen has served Asmara the way a grandmother serves her family — generously, slowly, and always with fresh injera. Our tsebhi simmers for hours over low heat, and our berbere is ground in-house every week.","Every meal ends the traditional way: a full coffee ceremony, beans roasted at your table, three rounds poured, no one in a hurry."],"signatures":["Zigni Beef","Tsebhi Dorho","Shiro","Coffee Ceremony"],"menu":[{"section":"Traditional Plates","items":[{"name":"Zigni","desc":"Slow-simmered beef in berbere sauce, served on injera","price":9},{"name":"Tsebhi Dorho","desc":"Chicken stew with hard-boiled egg and clarified butter","price":10},{"name":"Shiro","desc":"Silky chickpea purée with garlic and toasted spices","price":7},{"name":"Alicha Birsen","desc":"Mild lentil curry with turmeric and ginger","price":7}]},{"section":"To Share","items":[{"name":"Beyaynetu","desc":"Grand vegetarian platter — five stews on injera for two","price":16},{"name":"Kitcha Fit-fit","desc":"Torn flatbread tossed in spiced butter and yogurt","price":6}]},{"section":"To Finish","items":[{"name":"Coffee Ceremony","desc":"Beans roasted tableside, three traditional rounds","price":5},{"name":"Himbasha","desc":"Sweet celebration bread with cardamom","price":4}]}],"hours":[["Mon – Thu","11:00 – 22:00"],["Fri – Sat","11:00 – 23:30"],["Sunday","12:00 – 21:00"]],"gallery":[{"label":"The dining room","tone":"a"},{"label":"Injera, made daily","tone":"b"},{"label":"Coffee ceremony","tone":"c"},{"label":"The courtyard","tone":"d"}],"phone":"+291 1 12 34 56","address":"Harnet Avenue 42, Asmara, Eritrea","price_range":"$$","is_seed":tru