  ((select id from partners where name = 'Enda Silka' and business_type = 'restaurant'), 'restaurant', 'enda-silka', 'Enda Silka', 'Keren breakfast house — ful, silsi, and strong tea', false, 'sahel', '{"tagline":"Keren breakfast house — ful, silsi, and strong tea","cuisine":"Eritrean · Breakfast House","est":1981,"story":["Enda Silka opens before the Monday camel market does, and has for over forty years. Keren eats breakfast seriously — ful mashed at the table, silsi hot enough to wake you, bread straight from the oven next door.","Traders, drivers, and families share the long tables. You will too."],"signatures":["Shahan Ful","Silsi","Ga''at","Market-Day Breakfast"],"menu":[{"section":"Breakfast","items":[{"name":"Shahan Ful","desc":"Fava beans mashed tableside with oil, chili, onion, egg","price":3.5},{"name":"Silsi","desc":"Fiery tomato-berbere sauce with torn bread for dipping","price":3},{"name":"Ga''at","desc":"Barley porridge with a well of spiced butter and yogurt","price":4},{"name":"Frittata","desc":"Eggs scrambled with tomato, onion, and green pepper","price":3.5}]},{"section":"Market-Day Extras","items":[{"name":"Fata","desc":"Bread soaked in spiced yogurt sauce — Monday special","price":4},{"name":"Liver Tibsi","desc":"Quick-fried, onions and chili","price":5}]},{"section":"To Drink","items":[{"name":"Shahi Adey","desc":"Sweet spiced tea, the Keren way","price":0.5},{"name":"Bun","desc":"Coffee, roasted in the back room","price":1}]}],"hours":[["Mon – Sat","05:30 – 14:00"],["Sunday","06:30 – 12:00"]],"gallery":[{"label":"The long tables","tone":"a"},{"label":"Ful, mashed to order","tone":"b"},{"label":"Market morning rush","tone":"c"},{"label":"The tea kettles","tone":"d"}],"phone":"+291 1 40 08 51","address":"Market Square 12, Keren, Eritrea","price_range":"$","is_seed":true}'::jsonb),
