  ((select id from partners where name = 'Gurgusum Beach Kitchen' and business_type = 'restaurant'), 'restaurant', 'gurgusum-beach-kitchen', 'Gurgusum Beach Kitchen', 'Barefoot dining on the Gurgusum shore', false, 'dahlak', '{"tagline":"Barefoot dining on the Gurgusum shore","cuisine":"Beach Grill · Seafood","est":2019,"story":["Gurgusum Beach Kitchen is a grill, a shade canopy, and thirty steps of sand between your table and the Red Sea. We open when the afternoon heat breaks and cook until the last table leaves — Massawa keeps late hours, and so do we.","Swim first. The kingfish skewers taste better after."],"signatures":["Kingfish Skewers","Sunset Platter","Fresh Watermelon Juice"],"menu":[{"section":"Beach Grill","items":[{"name":"Kingfish Skewers","desc":"Cumin-lime marinade, grilled over driftwood coals","price":10},{"name":"Sunset Platter","desc":"Skewers, prawns, and grilled catch for two","price":22},{"name":"Spiced Chicken Wings","desc":"Berbere-honey glaze, charred edges","price":7}]},{"section":"Cold & Fresh","items":[{"name":"Red Sea Ceviche","desc":"Today''s white fish, lime, chili, red onion","price":9},{"name":"Watermelon & Feta","desc":"Ice-cold, mint, black pepper","price":5}]},{"section":"To Drink","items":[{"name":"Fresh Watermelon Juice","desc":"Pressed by the glass or the jug","price":2.5},{"name":"Mango Shake","desc":"Thick enough to need patience","price":3},{"name":"Shahi","desc":"Hot sweet tea, even on the beach","price":1}]}],"hours":[["Every day","16:00 – 01:00"]],"gallery":[{"label":"Thirty steps to the sea","tone":"a"},{"label":"Skewers over coals","tone":"b"},{"label":"Sunset from the canopy","tone":"c"},{"label":"The jug of watermelon","tone":"d"}],"phone":"+291 1 55 31 26","address":"Gurgusum Beach Road, Massawa, Eritrea","price_range":"$$","is_seed":true}'::jsonb);

-- ------------------------------------------------------------------
-- 5. Unique index on slug, now that both the backfill and the seed insert
-- above have given every row a value. Partial (where not null) rather than
-- a NOT NULL constraint — leaves room to tighten to NOT NULL in a later
-- migration once the human has confirmed in Supabase that no row (including
-- any added by hand between now and then) has a null slug.
-- ------------------------------------------------------------------
create unique index if not exists idx_listings_slug on listings(slug) where slug is not null;

-- ------------------------------------------------------------------
-- 6. RLS — additive only. Does not enable or disable RLS on any table:
-- since 002-004 aren't in this repo, this migration can't know whether
-- listings/bookings/guests currently have RLS enabled, and flipping that
-- switch here could silently break the live hotel booking flow. A new,
-- narrowly-scoped SELECT policy is safe to add either way (permissive
-- policies only ever expand access, never restrict) and closes the one
-- gap this migration can be sure of: a listings SELECT policy scoped to
-- hotels wouldn't cover listing_type = 'restaurant'.
--
-- Reservation requests reuse the same guests + bookings insert path
-- createBooking() already uses for hotels (see bookingApi.js) — if that
-- path is already RLS-safe for hotels (it must be; hotels are live), it's
-- RLS-safe for restaurants too, since neither guests nor bookings is
-- discriminated by listing_type. Confirm this from an anonymous/incognito
-- session per CLAUDE.md's hard-won lesson before treating step 5 as done.
-- ------------------------------------------------------------------
create policy "public read restaurant listings" on listings
  for select using (listing_type = 'restaurant');
